changeSet.sql:
-- Проверка 1: agreements ссылаются на существующий код медицинского покрытия
DO $$
DECLARE
    v_count INT;
    v_samples TEXT;
BEGIN
    SELECT COUNT(*)
    INTO v_count
    FROM agreements a
    WHERE NOT EXISTS (
        SELECT 1
        FROM medical_risk_limit_levels m
        WHERE m.code = a.medical_risk_limit_level
    );

    IF v_count > 0 THEN
        -- Собираем примеры для диагностики
        SELECT string_agg(DISTINCT a.medical_risk_limit_level, ', ')
        INTO v_samples
        FROM agreements a
        WHERE NOT EXISTS (
            SELECT 1
            FROM medical_risk_limit_levels m
            WHERE m.code = a.medical_risk_limit_level
        )
        LIMIT 10;

        RAISE EXCEPTION
            'Data quality check FAILED: % agreement(s) reference non-existent '
            'medical_risk_limit_level codes: [%]. '
            'Fix the data before re-running this migration.',
            v_count, v_samples;
    END IF;

    RAISE NOTICE 'Check 1 PASSED: all agreements.medical_risk_limit_level values exist in medical_risk_limit_levels.code';
END $$;

-- Проверка 2: agreements ссылаются на существующий ISO-код страны
DO $$
DECLARE
    v_count INT;
    v_samples TEXT;
BEGIN
    SELECT COUNT(*)
    INTO v_count
    FROM agreements a
    WHERE NOT EXISTS (
        SELECT 1
        FROM countries c
        WHERE c.iso_code = a.country_iso_code
    );

    IF v_count > 0 THEN
        SELECT string_agg(DISTINCT a.country_iso_code, ', ')
        INTO v_samples
        FROM agreements a
        WHERE NOT EXISTS (
            SELECT 1
            FROM countries c
            WHERE c.iso_code = a.country_iso_code
        )
        LIMIT 10;

        RAISE EXCEPTION
            'Data quality check FAILED: % agreement(s) reference non-existent '
            'country_iso_code values: [%]. '
            'Fix the data before re-running this migration.',
            v_count, v_samples;
    END IF;

    RAISE NOTICE 'Check 2 PASSED: all agreements.country_iso_code values exist in countries.iso_code';
END $$;

ALTER TABLE medical_risk_limit_levels
ADD CONSTRAINT uk_medical_level_code_unique
UNIQUE (code);

ALTER TABLE countries
ADD CONSTRAINT uk_country_iso_code_unique
UNIQUE (iso_code);
